import { useEffect, useRef, useState } from 'react';
import { createChart, CandlestickSeries, LineSeries, HistogramSeries } from 'lightweight-charts';
import styles from './CandleChart.module.css';
import { TIMEFRAMES } from '../utils/constants';

export default function CandleChart({ coin, prices, chartData, isLoading, timeframe, onTimeframe }) {
  const chartContainerRef = useRef(null);
  const chartRef          = useRef(null);
  const candleSeriesRef   = useRef(null);
  const volumeSeriesRef   = useRef(null);
  const lineSeriesRef     = useRef(null);

  const [activeIndicators, setActiveIndicators] = useState(['volume']);
  const [drawingMode, setDrawingMode]           = useState(false);

  const price  = prices[coin?.sym] || coin?.basePrice || 0;
  const change = coin?.change || 0;
  const isUp   = change >= 0;

  // Grafik oluştur
  useEffect(() => {
    if (!chartContainerRef.current) return;

    const chart = createChart(chartContainerRef.current, {
      layout: {
        background: { color: '#1e2329' },
        textColor: '#707a8a',
      },
      grid: {
        vertLines: { color: '#2b3139' },
        horzLines: { color: '#2b3139' },
      },
      crosshair: {
        mode: 1,
      },
      rightPriceScale: {
        borderColor: '#2b3139',
        textColor: '#707a8a',
      },
      timeScale: {
        borderColor: '#2b3139',
        textColor: '#707a8a',
        timeVisible: true,
        secondsVisible: false,
      },
      width:  chartContainerRef.current.clientWidth,
      height: 400,
    });

    const candleSeries = chart.addSeries(CandlestickSeries, {
      upColor:        '#0ecb81',
      downColor:      '#f6465d',
      borderUpColor:  '#0ecb81',
      borderDownColor:'#f6465d',
      wickUpColor:    '#0ecb81',
      wickDownColor:  '#f6465d',
    });

    const volumeSeries = chart.addSeries(HistogramSeries, {
      color:   '#26a69a',
      priceFormat: { type: 'volume' },
      priceScaleId: '',
    });

    chart.priceScale('').applyOptions({
      scaleMargins: { top: 0.8, bottom: 0 },
    });

    chartRef.current        = chart;
    candleSeriesRef.current = candleSeries;
    volumeSeriesRef.current = volumeSeries;

    // Responsive
    const resizeObserver = new ResizeObserver(entries => {
      for (const entry of entries) {
        chart.applyOptions({ width: entry.contentRect.width });
      }
    });
    resizeObserver.observe(chartContainerRef.current);

    return () => {
      resizeObserver.disconnect();
      chart.remove();
    };
  }, []);

  // Veri güncelle
  useEffect(() => {
    if (!chartData || !candleSeriesRef.current || !volumeSeriesRef.current) return;

    const candles = generateCandles(chartData.prices);
    candleSeriesRef.current.setData(candles);

    const volumes = candles.map((c, i) => ({
      time:  c.time,
      value: Math.abs(c.close - c.open) * (Math.random() * 1000 + 500),
      color: c.close >= c.open ? 'rgba(14,203,129,0.4)' : 'rgba(246,70,93,0.4)',
    }));
    volumeSeriesRef.current.setData(volumes);

    chartRef.current?.timeScale().fitContent();
  }, [chartData]);

  const toggleIndicator = (ind) => {
    setActiveIndicators(prev =>
      prev.includes(ind) ? prev.filter(i => i !== ind) : [...prev, ind]
    );
  };

  const formatPrice = (n) => {
    if (!n) return '$—';
    if (n >= 10000) return '$' + n.toLocaleString('tr-TR', { maximumFractionDigits: 0 });
    if (n >= 1)     return '$' + n.toFixed(2);
    return '$' + n.toFixed(4);
  };

  return (
    <div className={styles.panel}>
      {/* Üst bar */}
      <div className={styles.topBar}>
        <div className={styles.coinInfo}>
          <div className={styles.coinName}>{coin?.sym}/USDT</div>
          <div className={styles.coinPrice}>{formatPrice(price)}</div>
          <div className={`${styles.change} ${isUp ? styles.up : styles.down}`}>
            {isUp ? '▲' : '▼'} {Math.abs(change).toFixed(2)}%
          </div>
        </div>

        {/* Zaman dilimleri */}
        <div className={styles.tfBtns}>
          {TIMEFRAMES.map(tf => (
            <button
              key={tf.value}
              className={`${styles.tfBtn} ${timeframe === tf.value ? styles.active : ''}`}
              onClick={() => onTimeframe(tf.value)}
            >
              {tf.label}
            </button>
          ))}
        </div>
      </div>

      {/* İndikatör butonları */}
      <div className={styles.indicatorBar}>
        <span className={styles.indBarLabel}>İndikatörler:</span>
        {['EMA20', 'EMA50', 'BB', 'volume'].map(ind => (
          <button
            key={ind}
            className={`${styles.indBtn} ${activeIndicators.includes(ind) ? styles.indActive : ''}`}
            onClick={() => toggleIndicator(ind)}
          >
            {ind}
          </button>
        ))}
        <div className={styles.divider} />
        <button
          className={`${styles.drawBtn} ${drawingMode ? styles.drawActive : ''}`}
          onClick={() => setDrawingMode(!drawingMode)}
        >
          ✏️ {drawingMode ? 'Çizim Modu Açık' : 'Çizim Modu'}
        </button>
        {drawingMode && (
          <span className={styles.drawHint}>Grafik üzerine tıklayarak çizgi çizebilirsin</span>
        )}
      </div>

      {/* Grafik */}
      <div className={styles.chartWrap}>
        {isLoading && (
          <div className={styles.loading}>
            <div className={styles.spinner} />
            <span>Yükleniyor...</span>
          </div>
        )}
        <div ref={chartContainerRef} className={styles.chart} />
      </div>
    </div>
  );
}

// Fiyat verisinden mum verisi üret
function generateCandles(prices) {
  const now     = Math.floor(Date.now() / 1000);
  const interval = 60;
  return prices.map((close, i) => {
    const open  = i === 0 ? close : prices[i - 1];
    const high  = Math.max(open, close) * (1 + Math.random() * 0.003);
    const low   = Math.min(open, close) * (1 - Math.random() * 0.003);
    return {
      time:  now - (prices.length - i) * interval,
      open:  parseFloat(open.toFixed(6)),
      high:  parseFloat(high.toFixed(6)),
      low:   parseFloat(low.toFixed(6)),
      close: parseFloat(close.toFixed(6)),
    };
  });
}
